import React from 'react';
import { useWebSocket } from '../hooks/useWebSocket';

const DashboardOverview = () => {
    const { data } = useWebSocket("ws://localhost:8000/ws");

    if (!data) return (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-pulse">
            {[...Array(3)].map((_, i) => (
                <div key={i} className="glass-panel rounded-xl p-6 min-h-[160px] bg-white/5" />
            ))}
        </div>
    );

    const activeAgentsPercent = Math.round((data.current_metrics.active_agents / 5) * 100);

    return (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {/* Active Agents */}
            <div className="glass-panel rounded-xl p-6 flex flex-col justify-between min-h-[160px]">
                <p className="text-slate-400 text-xs font-mono tracking-wider mb-4 uppercase">ACTIVE_AGENTS</p>
                <div className="flex items-center justify-between mt-auto">
                    <div className="w-16 h-16 rounded-full border-4 border-dashed border-white flex items-center justify-center">
                        <span className="material-symbols-outlined text-white text-2xl">memory</span>
                    </div>
                    <p className="text-white text-4xl font-mono font-bold">{activeAgentsPercent}%</p>
                </div>
            </div>

            {/* Database Load */}
            <div className="glass-panel rounded-xl p-6 flex flex-col justify-between min-h-[160px]">
                <p className="text-slate-400 text-xs font-mono tracking-wider mb-4 uppercase">DATABASE_LOAD</p>
                <div className="mt-auto w-full">
                    <div className="flex justify-between text-xs font-mono text-slate-300 mb-2 uppercase">
                        <span>OPT-ROUTING</span>
                        <span>ACTIVE</span>
                    </div>
                    <div className="flex gap-1 h-3 w-full">
                        {[...Array(6)].map((_, i) => {
                            const isActive = i < Math.ceil((data.current_metrics.db_load / 100) * 6);
                            return (
                                <div
                                    key={i}
                                    className={`h-full flex-1 rounded-sm transition-colors duration-500 ${isActive ? 'bg-white' : 'bg-slate-800'}`}
                                />
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Cost Savings */}
            <div className="glass-panel rounded-xl p-6 flex flex-col justify-between min-h-[160px]">
                <p className="text-slate-400 text-xs font-mono tracking-wider mb-4 uppercase">COST_SAVINGS</p>
                <div className="mt-auto">
                    <div className="flex items-center gap-2 text-green-400 mb-1">
                        <span className="material-symbols-outlined text-sm">trending_up</span>
                        <span className="text-xs font-mono">+12.4%</span>
                    </div>
                    <p className="text-white text-4xl font-mono font-bold italic">
                        +${data.current_metrics.cost_savings_usd.toLocaleString()}
                    </p>
                </div>
            </div>
        </div>
    );
};

export default DashboardOverview;
